SELECT "Meter Reading (MR) Doc. No.", HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1_cust AS POST_CODE1, CITY1_cust AS CITY1, CITY2_cust AS CITY2, EMAIL
FROM J09D_temp
WHERE ENTSCHEIDUNG = 'MANDATORY_READING';

SELECT "Meter Reading (MR) Doc. No.", HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1_cust AS POST_CODE1, CITY1_cust AS CITY1, CITY2_cust AS CITY2, EMAIL
FROM J09D_temp
WHERE ENTSCHEIDUNG = 'DIRECT_MAIL';

SELECT "Meter Reading (MR) Doc. No.", HAUS, ANLAGE, ME_MA_ID, EQUNR, HOUSE_NUM1, ENTSCHEIDUNG, TITLE, FORENAME, SURNAME, STREET, STREETNO, POST_CODE1_cust AS POST_CODE1, CITY1_cust AS CITY1, CITY2_cust AS CITY2, EMAIL
FROM J09D_temp
WHERE ENTSCHEIDUNG NOT IN ('MANDATORY_READING','DIRECT_MAIL') OR ENTSCHEIDUNG IS NULL;
